 19	import chart_color_blue_300 from '@patternfly/react-tokens/dist/esm/chart_color_blue_300';
 20	import chart_color_orange_300 from '@patternfly/react-tokens/dist/esm/chart_color_orange_300';
 21	import useDuration from '@virtualmachines/details/tabs/metrics/hooks/useDuration';
 22	
 23	import ComponentReady from '../ComponentReady/ComponentReady';
 24	import useResponsiveCharts from '../hooks/useResponsiveCharts';
 25	import { getUtilizationQueries } from '../utils/queries';
 26	import {
 27	  findMaxYValue,
 28	  MILLISECONDS_MULTIPLIER,
 29	  queriesToLink,
 30	  tickFormat,
 31	  TICKS_COUNT,
 32	} from '../utils/utils';
 33	
 34	type StorageTotalReadWriteThresholdChartProps = {
 35	  vmi: V1VirtualMachineInstance;
 36	};
 37	
 38	const StorageTotalReadWriteThresholdChart: React.FC<StorageTotalReadWriteThresholdChartProps> = ({
 39	  vmi,
 40	}) => {
 41	  const { t } = useKubevirtTranslation();
 42	  const { currentTime, duration, timespan } = useDuration();
 43	  const queries = React.useMemo(
 44	    () => getUtilizationQueries({ duration, obj: vmi }),
 45	    [vmi, duration],
 46	  );
 47	
 48	  const { height, ref, width } = useResponsiveCharts();
 49	
 50	  const [data] = usePrometheusPoll({
 51	    endpoint: PrometheusEndpoint?.QUERY_RANGE,
 52	    endTime: currentTime,
 53	    namespace: vmi?.metadata?.namespace,
 54	    query: queries?.FILESYSTEM_TOTAL_USAGE,
 55	    timespan,
 56	  });
 57	
 58	  const storageWriteData = data?.data?.result?.[0]?.values;
 59	
 60	  const chartData = storageWriteData?.map(([x, y]) => {
 61	    return { x: new Date(x * MILLISECONDS_MULTIPLIER), y: Number(y) };
 62	  });
 63	  const yMax = findMaxYValue(chartData);
 64	
 65	  const thresholdData = storageWriteData?.map(([x]) => {
 66	    return { x: new Date(x * MILLISECONDS_MULTIPLIER), y: yMax };
 67	  });
 68	  const linkToMetrics = queriesToLink(queries.FILESYSTEM_TOTAL_USAGE);
 69	  return (
 70	    <ComponentReady isReady={!isEmpty(chartData)} linkToMetrics={linkToMetrics}>
 71	      <div className="util-threshold-chart" ref={ref}>
 72	        <Link to={linkToMetrics}>
 73	          <Chart
 74	            containerComponent={
 75	              <ChartVoronoiContainer
 76	                labels={({ datum }) =>
 77	                  t('Data transfer: {{input}}', {
 78	                    input: xbytes(datum?.y, { fixed: 2, iec: true }),
 79	                  })
 80	                }
 81	                constrainToVisibleArea
 82	              />
 83	            }
 84	            domain={{
 85	              x: [currentTime - timespan, currentTime],
 86	              y: [0, yMax],
 87	            }}
 88	            height={height}
 89	            padding={{ bottom: 35, left: 70, right: 35, top: 35 }}
 90	            scale={{ x: 'time', y: 'linear' }}
 91	            width={width}
 92	          >
 93	            <ChartAxis
 94	              style={{
 95	                grid: {
 96	                  stroke: chart_color_black_200.value,
 97	                },
 98	                tickLabels,
 99	              }}
100	              dependentAxis
101	              tickFormat={(tick: number) => xbytes(tick, { fixed: 2, iec: true })}
102	              tickValues={[0, yMax]}
103	            />
104	            <ChartAxis
105	              style={{
106	                tickLabels: { padding: 2, ...tickLabels },
107	                ticks: { stroke: 'transparent' },
108	              }}
109	              axisComponent={<></>}
110	              tickCount={TICKS_COUNT}
111	              tickFormat={tickFormat(duration, currentTime)}
112	            />
113	            <ChartGroup>
114	              <ChartArea
115	                style={{
116	                  data: {
117	                    stroke: chart_color_blue_300.value,
118	                  },
119	                }}
120	                data={chartData}
121	              />
122	            </ChartGroup>
123	            <ChartThreshold
124	              style={{
125	                data: {
126	                  stroke: chart_color_orange_300.value,
127	                  strokeDasharray: 10,
128	                },
129	              }}
130	              data={thresholdData}
131	            />
132	          </Chart>
133	        </Link>
134	      </div>
135	    </ComponentReady>
136	  );
137	};
138	
139	export default StorageTotalReadWriteThresholdChart;

